import React, { useState, useEffect } from "react";
import { Card, Form, Button, Container, Row, Col, Alert } from "react-bootstrap";
import { useParams, useNavigate } from "react-router-dom";
import Header from "../../components/Headers/Header";
import axios from "axios";

const EditDrug = () => {
    const { id } = useParams(); // Lấy id thuốc từ URL
    const navigate = useNavigate();

    const [drug, setDrug] = useState({
        medicine_code: "",
        medicine_name: "",
        medicine_type_name: "",
        price: 0,
        unit: "",
        description: ""
    });

    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [success, setSuccess] = useState(false);

    // Lấy thông tin thuốc cần chỉnh sửa khi component mount
    useEffect(() => {
        const fetchDrugDetails = async () => {
            setLoading(true);
            try {
                // Đảm bảo URL API đúng và server đang chạy
                console.log(`Đang gọi API: http://localhost:5001/api/medicine/${id}`);
                const response = await axios.get(`http://localhost:5001/api/medicine/${id}`);
                console.log("Dữ liệu nhận được:", response.data);

                if (response.data && response.data.data) {
                    setDrug(response.data.data);
                } else {
                    setError("Không tìm thấy thông tin thuốc");
                }
            } catch (err) {
                console.error("Lỗi khi lấy thông tin thuốc:", err);

                // Hiển thị thông tin lỗi chi tiết hơn
                if (err.response) {
                    // Server trả về lỗi với mã status
                    setError(`Lỗi từ server: ${err.response.status} - ${err.response.statusText}`);
                } else if (err.request) {
                    // Không nhận được phản hồi từ server
                    setError("Không thể kết nối đến server API. Vui lòng kiểm tra server có đang chạy không.");
                } else {
                    // Lỗi khác
                    setError(`Lỗi: ${err.message}`);
                }
            } finally {
                setLoading(false);
            }
        };

        fetchDrugDetails();
    }, [id]);

    // Xử lý thay đổi các trường dữ liệu
    const handleChange = (e) => {
        const { name, value } = e.target;
        setDrug({
            ...drug,
            [name]: name === "price" ? Number(value) : value
        });
    };

    // Xử lý lưu thay đổi
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            const response = await axios.put(`http://localhost:5001/api/medicine/${id}`, drug);
            console.log("Kết quả cập nhật:", response.data);
            setSuccess(true);
            // Hiển thị thông báo thành công trong 2 giây trước khi chuyển hướng
            setTimeout(() => {
                navigate("/drugs");
            }, 2000);
        } catch (err) {
            console.error("Lỗi khi cập nhật thuốc:", err);

            if (err.response) {
                setError(`Lỗi từ server: ${err.response.status} - ${err.response.statusText}`);
            } else if (err.request) {
                setError("Không thể kết nối đến server API.");
            } else {
                setError(`Lỗi: ${err.message}`);
            }
        }
    };

    // Xử lý hủy và quay lại trang danh sách
    const handleCancel = () => {
        navigate("/drugs");
    };

    // Hiển thị trang với thông tin lỗi
    if (error) {
        return (
            <>
                <Header />
                <Container className="mt-4">
                    <Card>
                        <Card.Header className="bg-primary text-white">
                            <h5 className="mb-0">Chỉnh Sửa Thông Tin Thuốc</h5>
                        </Card.Header>
                        <Card.Body>
                            <Alert variant="danger">
                                <h5>Không thể tải thông tin thuốc</h5>
                                <p>{error}</p>
                                <div className="mt-3">
                                    <Button variant="secondary" onClick={() => navigate("/drugs")}>
                                        Quay lại danh sách thuốc
                                    </Button>
                                </div>
                            </Alert>
                        </Card.Body>
                    </Card>
                </Container>
            </>
        );
    }

    return (
        <>
            <Header />
            <Container className="mt-4">
                <Card>
                    <Card.Header className="bg-primary text-white">
                        <h5 className="mb-0">Chỉnh Sửa Thông Tin Thuốc</h5>
                    </Card.Header>
                    <Card.Body>
                        {loading ? (
                            <div className="text-center py-4">
                                <div className="spinner-border text-primary" role="status">
                                    <span className="visually-hidden">Đang tải...</span>
                                </div>
                                <p className="mt-2">Đang tải thông tin thuốc...</p>
                            </div>
                        ) : success ? (
                            <Alert variant="success">
                                Cập nhật thông tin thuốc thành công! Đang chuyển hướng...
                            </Alert>
                        ) : (
                            <Form onSubmit={handleSubmit}>
                                <Row>
                                    <Col md={6}>
                                        <Form.Group className="mb-3">
                                            <Form.Label>Mã thuốc</Form.Label>
                                            <Form.Control
                                                type="text"
                                                name="medicine_code"
                                                value={drug.medicine_code || ""}
                                                onChange={handleChange}
                                                disabled // Thường mã thuốc không được sửa
                                            />
                                        </Form.Group>
                                    </Col>
                                    <Col md={6}>
                                        <Form.Group className="mb-3">
                                            <Form.Label>Tên thuốc</Form.Label>
                                            <Form.Control
                                                type="text"
                                                name="medicine_name"
                                                value={drug.medicine_name || ""}
                                                onChange={handleChange}
                                                required
                                            />
                                        </Form.Group>
                                    </Col>
                                </Row>

                                <Row>
                                    <Col md={6}>
                                        <Form.Group className="mb-3">
                                            <Form.Label>Loại thuốc</Form.Label>
                                            <Form.Control
                                                type="text"
                                                name="medicine_type_name"
                                                value={drug.medicine_type_name || ""}
                                                onChange={handleChange}
                                                required
                                            />
                                        </Form.Group>
                                    </Col>
                                    <Col md={6}>
                                        <Form.Group className="mb-3">
                                            <Form.Label>Đơn vị tính</Form.Label>
                                            <Form.Control
                                                type="text"
                                                name="unit"
                                                value={drug.unit || ""}
                                                onChange={handleChange}
                                                required
                                            />
                                        </Form.Group>
                                    </Col>
                                </Row>

                                <Form.Group className="mb-3">
                                    <Form.Label>Giá (VNĐ)</Form.Label>
                                    <Form.Control
                                        type="number"
                                        name="price"
                                        value={drug.price || 0}
                                        onChange={handleChange}
                                        required
                                        min="0"
                                    />
                                </Form.Group>

                                <Form.Group className="mb-3">
                                    <Form.Label>Mô tả</Form.Label>
                                    <Form.Control
                                        as="textarea"
                                        rows={3}
                                        name="description"
                                        value={drug.description || ""}
                                        onChange={handleChange}
                                    />
                                </Form.Group>

                                <div className="d-flex justify-content-end gap-2 mt-4">
                                    <Button variant="secondary" onClick={handleCancel}>
                                        Thoát
                                    </Button>
                                    <Button variant="primary" type="submit">
                                        Lưu thuốc
                                    </Button>
                                </div>
                            </Form>
                        )}
                    </Card.Body>
                </Card>
            </Container>
        </>
    );
};

export default EditDrug;
